package app.org.apache.roller.weblogger.ui.core.filters;

public class IPBanFilter implements Filter { private static Log log = LogFactory . getLog ( IPBanFilter . class ) ; public void init ( FilterConfig filterConfig ) throws ServletException { log . info ( "INIT IPBanFilter" ) ; } public void doFilter ( ServletRequest req , ServletResponse res , FilterChain chain ) throws IOException , ServletException { HttpServletRequest request = ( HttpServletRequest ) req ; HttpServletResponse response = ( HttpServletResponse ) res ; if ( IPBanList . getInstance ( ) . isBanned ( request . getRemoteAddr ( ) ) ) { log . debug ( "BANNED " + request . getRemoteAddr ( ) ) ; response . sendError ( HttpServletResponse . SC_NOT_FOUND ) ; return ; } else { chain . doFilter ( request , response ) ; } } public void destroy ( ) { } }